import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    private static final String BASE_PATH = "C:/myfiles/";

    public static void main(String[] args) {
        if (args.length < 1) {
            System.out.println("Usage: java SecurePathTraversal <filename>");
            return;
        }

        String fileName = args[0];

        try {
            Path filePath = Paths.get(BASE_PATH, fileName).normalize();

            if (!filePath.startsWith(Paths.get(BASE_PATH))) {
                System.out.println("Invalid file path specified.");
                return;
            }

            BufferedReader br = new BufferedReader(new FileReader(filePath.toFile()));
            String line;
            while ((line = br.readLine()) != null) {
                System.out.println(line);
            }
            br.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

}

